12	import type {
13	  StartupContext,
14	  LoadedKit,
15	  LoadedApparatus,
16	  FailedPlugin,
17	} from '@shardworks/nexus-core';
18	
19	// ── Types ────────────────────────────────────────────────────────────
20	
